import { getProjectHash } from "@google/gemini-cli-core/dist/src/utils/paths.js";
import {
  analyzeInParallel,
  formatBytes,
  readAndFormatChatLog,
  runWithRetry,
  MAX_AGGREGATION_BYTES
} from "./analysis-utils.js";
import type { BaseProcessResult } from "./analysis-utils.js";
import { GoogleGenAI, Type } from "@google/genai";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";
import { parseArgs } from "node:util";

const ANALYSIS_MODEL = "gemini-3-flash-preview";
const AGGREGATION_MODEL = "gemini-3-pro-preview";
const MAX_TOTAL_RETRIES = 10;
const MAX_RETRIES_PER_REQUEST = 3;

interface FrictionInsight {
  sessionFile?: string;
  friction_points?: Array<{
    task_description: string;
    friction_type:
      | "autonomous_retry"
      | "user_intervention"
      | "hunting"
      | "repetition"
      | "tool_failure"
      | "other";
    root_cause:
      | "environment_issue"
      | "model_hallucination"
      | "tool_limitation"
      | "user_ambiguity"
      | "complex_task"
      | "unknown";
    user_sentiment: "frustrated" | "helpful" | "neutral" | "absent";
    severity: "low" | "medium" | "high";
    resolution: "success" | "failure" | "partial";
    details: string;
    user_quote?: string;
  }>;
}

function usage() {
  const scriptName = path.basename(process.argv[1]);
  console.log(`Usage: ${scriptName} [OPTIONS] DIRECTORY OUTPUT_FILE

Extracts "friction" insights from Gemini CLI logs for a given directory.
Focuses on identifying tasks where the agent had to retry, hunt for information, or required user intervention.

Arguments:
  DIRECTORY         The directory to look up history for.
  OUTPUT_FILE       The path to write the Markdown report to.

Options:
  --limit NUMBER        Limit analysis to the N most recent conversations (default: all).
  --dump-analysis FILE  Output intermediate analysis data to FILE (Markdown format).
  -h, --help            Display this help message and exit

Environment:
  GEMINI_API_KEY    Required. Your Gemini API key.
`);
}

async function main() {
  const { values, positionals } = parseArgs({
    options: {
      help: { type: "boolean", short: "h" },
      limit: { type: "string" },
      "dump-analysis": { type: "string" }
    },
    allowPositionals: true
  });

  if (values.help) {
    usage();
    process.exit(0);
  }

  if (positionals.length < 2) {
    usage();
    process.exit(1);
  }

  const targetDirArg = positionals[0];
  const outputFile = positionals[1];
  const apiKey = process.env.GEMINI_API_KEY;

  if (!apiKey) {
    console.error("Error: GEMINI_API_KEY environment variable not set.");
    process.exit(1);
  }

  const genAI = new GoogleGenAI({ apiKey });

  const resolvedTargetDir = path.resolve(targetDirArg);
  if (
    !fs.existsSync(resolvedTargetDir) ||
    !fs.statSync(resolvedTargetDir).isDirectory()
  ) {
    console.error(`Error: Directory '${resolvedTargetDir}' does not exist.`);
    process.exit(1);
  }

  const hash = getProjectHash(resolvedTargetDir);
  const geminiTmp = path.join(os.homedir(), ".gemini/tmp", hash);
  const chatsDir = path.join(geminiTmp, "chats");

  if (!fs.existsSync(chatsDir)) {
    console.error(`Error: No 'chats' subdirectory found in: ${geminiTmp}`);
    process.exit(0);
  }

  let chatFiles = fs
    .readdirSync(chatsDir)
    .filter((f) => f.endsWith(".json"))
    .map((f) => ({
      name: f,
      path: path.join(chatsDir, f),
      time: fs.statSync(path.join(chatsDir, f)).mtime.getTime()
    }))
    .sort((a, b) => b.time - a.time); // Newest first

  const totalFoundCount = chatFiles.length;

  if (totalFoundCount === 0) {
    console.log("No chat logs found.");
    process.exit(0);
  }

  // Filter based on limit
  if (values.limit) {
    const limit = parseInt(values.limit, 10);
    if (isNaN(limit) || limit <= 0) {
      console.error("Invalid limit specified.");
      process.exit(1);
    }
    chatFiles = chatFiles.slice(0, limit);
    console.error(`Analyzing most recent ${chatFiles.length} logs...`);
  } else {
    console.error(`Analyzing all ${chatFiles.length} logs...`);
  }

  const selectedCount = chatFiles.length;

  // Global retry counter for this run
  let totalRetries = 0;

  const processLogFileWrapper = async (
    filePath: string
  ): Promise<BaseProcessResult<FrictionInsight> | null> => {
    return runWithRetry(() => processLogFile(filePath, genAI), {
      maxRetries: MAX_RETRIES_PER_REQUEST,
      onRetry: () => {
        totalRetries++;
        if (totalRetries > MAX_TOTAL_RETRIES) {
          console.error(
            `\nMax total retries (${MAX_TOTAL_RETRIES}) exceeded. Skipping ${path.basename(filePath)}.`
          );
          return false; // Stop retrying
        }
        return true; // Continue retrying
      }
    });
  };

  const {
    results: frictionInsights,
    totalRawBytes,
    totalFilteredBytes,
    totalSummarizedBytes,
    failedCount,
    skippedCount
  } = await analyzeInParallel(
    chatFiles.map((f) => f.path),
    processLogFileWrapper
  );

  if (frictionInsights.length === 0) {
    console.log("No insights extracted.");
    process.exit(0);
  }

  if (values["dump-analysis"]) {
    let rawOutput = "# Raw Friction Analysis Output\n\n";
    for (const insight of frictionInsights) {
      if (insight.sessionFile) {
        rawOutput += `## Session: ${path.basename(insight.sessionFile)}\n\n`;
      } else {
        rawOutput += `## Session: Unknown\n\n`;
      }

      if (insight.friction_points && insight.friction_points.length > 0) {
        rawOutput += "```json\n";
        rawOutput += JSON.stringify(insight.friction_points, null, 2);
        rawOutput += "\n```\n\n";
      } else {
        rawOutput += "_No friction detected._\n\n";
      }
      rawOutput += "---\n\n";
    }
    fs.writeFileSync(values["dump-analysis"], rawOutput);
    console.error(`Raw output written to: ${values["dump-analysis"]}`);
  }

  console.error("\nAggregating insights...");
  const finalReport = await aggregateInsights(frictionInsights, genAI, {
    directory: resolvedTargetDir,
    totalFound: totalFoundCount,
    selectedCount: selectedCount,
    analyzedCount: frictionInsights.length,
    failedCount: failedCount,
    skippedCount: skippedCount,
    totalRawBytes,
    totalFilteredBytes,
    totalSummarizedBytes
  });

  fs.writeFileSync(outputFile, finalReport);
  console.log(`Report written to: ${outputFile}`);
}

async function processLogFile(
  filePath: string,
  genAI: GoogleGenAI
): Promise<BaseProcessResult<FrictionInsight> | null> {
  const resultData = readAndFormatChatLog(filePath);
  if (!resultData) return null;

  const { content: transcript, rawSize, filteredSize } = resultData;

  const prompt = `
<role>
You are an expert software engineering analyst specializing in evaluating AI agent performance and identifying friction points.
</role>

<instructions>
1. **Plan**: Read the entire log to understand the user's ultimate goal and the agent's strategy.
2. **Execute**: Identify specific moments where the interaction broke down or slowed down.
    - **Friction Definition**:
        - **Autonomous Retries**: Loops or repeated variations without success.
        - **User Intervention**: User corrects, interrupts, or guides the agent.
        - **Hunting**: Blind searching (grep/find) for information.
        - **Tool Failure**: Tools crashing or returning useless data.
        - **Repetition**: Repeating the same mistake.
3. **Analyze Root Cause**: For each friction point, determine *why* it happened (e.g., did the tool crash? did the model hallucinate a command?).
4. **Assess User Sentiment**: Look at the user's language. Are they frustrated ("stop!", "no"), helpful ("try this"), or neutral?
5. **Validate**: Ensure the severity matches the disruption. High severity means the user *had* to intervene or the task failed.
</instructions>

<constraints>
- Output must be valid JSON matching the provided schema.
- Be specific in 'details'. Don't just say "it failed", say "it failed because ANDROID_SERIAL was missing".
</constraints>

<log_excerpt>
${transcript}
</log_excerpt>
`;

  const result = await genAI.models.generateContent({
    model: ANALYSIS_MODEL,
    contents: [{ role: "user", parts: [{ text: prompt }] }],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          friction_points: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                task_description: { type: Type.STRING },
                friction_type: {
                  type: Type.STRING,
                  enum: [
                    "autonomous_retry",
                    "user_intervention",
                    "hunting",
                    "repetition",
                    "tool_failure",
                    "other"
                  ]
                },
                root_cause: {
                  type: Type.STRING,
                  enum: [
                    "environment_issue",
                    "model_hallucination",
                    "tool_limitation",
                    "user_ambiguity",
                    "complex_task",
                    "unknown"
                  ]
                },
                user_sentiment: {
                  type: Type.STRING,
                  enum: ["frustrated", "helpful", "neutral", "absent"]
                },
                severity: {
                  type: Type.STRING,
                  enum: ["low", "medium", "high"]
                },
                resolution: {
                  type: Type.STRING,
                  enum: ["success", "failure", "partial"]
                },
                details: { type: Type.STRING },
                user_quote: { type: Type.STRING }
              },
              required: [
                "task_description",
                "friction_type",
                "root_cause",
                "user_sentiment",
                "severity",
                "resolution",
                "details"
              ]
            }
          }
        }
      }
    }
  });

  const text = result.text;
  if (!text) return null;

  let data;
  try {
    data = JSON.parse(text);
  } catch {
    console.error(`Failed to parse JSON for ${path.basename(filePath)}`);
    return null;
  }

  data.sessionFile = filePath;

  return {
    insight: data,
    rawSize: rawSize,
    filteredSize: filteredSize
  };
}

async function aggregateInsights(
  insights: FrictionInsight[],
  genAI: GoogleGenAI,
  metadata: {
    directory: string;
    totalFound: number;
    selectedCount: number;
    analyzedCount: number;
    failedCount: number;
    skippedCount: number;
    totalRawBytes: number;
    totalFilteredBytes: number;
    totalSummarizedBytes: number;
  }
): Promise<string> {
  const sessionData = insights
    .map((insight) => ({
      session: insight.sessionFile
        ? path.basename(insight.sessionFile)
        : "unknown",
      friction_points: insight.friction_points || []
    }))
    .filter((s) => s.friction_points.length > 0); // Only include sessions with friction

  // Calculate friction stats
  const frictionCounts: Record<string, number> = {
    autonomous_retry: 0,
    user_intervention: 0,
    hunting: 0,
    repetition: 0,
    tool_failure: 0,
    other: 0
  };
  const rootCauseCounts: Record<string, number> = {
    environment_issue: 0,
    model_hallucination: 0,
    tool_limitation: 0,
    user_ambiguity: 0,
    complex_task: 0,
    unknown: 0
  };
  let totalFrictionPoints = 0;

  for (const insight of insights) {
    if (insight.friction_points) {
      for (const point of insight.friction_points) {
        if (point.friction_type && point.friction_type in frictionCounts) {
          frictionCounts[point.friction_type]++;
        } else {
          frictionCounts["other"]++;
        }

        if (point.root_cause && point.root_cause in rootCauseCounts) {
          rootCauseCounts[point.root_cause]++;
        } else {
          rootCauseCounts["unknown"]++;
        }
        totalFrictionPoints++;
      }
    }
  }

  const inputData = JSON.stringify(sessionData, null, 2);
  const inputSize = Buffer.byteLength(inputData, "utf8");

  console.error(`Aggregation Input Size: ${inputSize} bytes`);

  if (inputSize > MAX_AGGREGATION_BYTES) {
    console.error(
      `WARNING: Input data (${inputSize} bytes) exceeds the limit of ${MAX_AGGREGATION_BYTES} bytes. Aggregation might fail.`
    );
  }

  const now = new Date().toISOString().slice(0, 16).replace("T", " ");

  const prompt = `
<role>
You are a Product Manager and UX Researcher for an "AI for Android Development" platform.
</role>

<context>
Target Directory: ${metadata.directory}
Analysis Date: ${now}
Input Statistics:
- Total Logs Found: ${metadata.totalFound}
- Logs Selected for Analysis: ${metadata.selectedCount}
- Successfully Analyzed: ${metadata.analyzedCount}
- Failed Analysis: ${metadata.failedCount}
- Skipped (Size Limit Reached): ${metadata.skippedCount}

Friction Statistics:
- Total Friction Points: ${totalFrictionPoints}
- Autonomous Retries: ${frictionCounts.autonomous_retry}
- User Interventions: ${frictionCounts.user_intervention}
- Hunting: ${frictionCounts.hunting}
- Repetition: ${frictionCounts.repetition}
- Tool Failures: ${frictionCounts.tool_failure}

Root Cause Statistics:
- Environment Issues: ${rootCauseCounts.environment_issue}
- Model Hallucinations: ${rootCauseCounts.model_hallucination}
- Tool Limitations: ${rootCauseCounts.tool_limitation}
- User Ambiguity: ${rootCauseCounts.user_ambiguity}
- Complex Tasks: ${rootCauseCounts.complex_task}

Data Volume:
- Total Raw Input Log Size: ${formatBytes(metadata.totalRawBytes)}
- Total Filtered Input Size (for Analysis): ${formatBytes(metadata.totalFilteredBytes)}
- Total Summarized Input Size (for Aggregation): ${formatBytes(metadata.totalSummarizedBytes)}
- Compression Ratio (Raw -> Summary): ${(metadata.totalRawBytes / metadata.totalSummarizedBytes || 0).toFixed(1)}x
</context>

<instructions>
Synthesize the provided JSON list of "Agent Friction Points" into a comprehensive "Friction & Failure Post-Mortem".
The goal is to identify systemic patterns in *why* the agent fails and *how* users react.

**Report Structure:**

1.  **Header**:
    *   Title: "# Gemini CLI Friction Post-Mortem"
    *   Date: "Date: ${now}"
    *   Target Directory: "Target Directory: ${metadata.directory}"
2.  **Executive Summary**: Is the agent reliable? What is the dominant failure mode?
3.  **Root Cause Analysis**:
    *   Analyze the provided "Root Cause Statistics".
    *   Are failures mostly due to the *environment* (flaky tools, network) or the *model* (hallucination, confusion)?
    *   *Insight*: If Environment Issues are high, we need better tools. If Model Hallucinations are high, we need better prompts.
4.  **Tool Reliability Analysis**:
    *   Identify which specific tools failed most often (e.g., \`write_file\`, \`replace\`, \`adb\`, \`python\`).
    *   Describe the failure mode for the top failing tools.
    *   *Example*: "The \`write_file\` tool frequently caused syntax errors when generating Python scripts."
5.  **User Sentiment & Intervention**:
    *   When users intervene, are they **frustrated** (shouting, stopping) or **helpful** (guiding)?
    *   What triggers the most frustration? (e.g., Infinite loops? Deleting files?)
6.  **Critical Failure Categories**:
    *   Group the specific incidents into categories (e.g., "Deployment Hell", "Ghost Bugs", "Context Loss").
    *   Provide specific examples from the logs.
6.  **"Hunting" Patterns**:
    *   What information is the agent blindly searching for?
    *   Why is it hard to find?
7.  **Action Plan**:
    *   **P0 (Critical)**: Immediate fixes for high-severity/frustration items.
    *   **P1 (Strategic)**: New tools or capabilities to address root causes.
    *   **P2 (UX)**: Improvements to error messages or recovery flows.

**Tone**: Honest, critical, engineering-focused.
</instructions>

<input_data>
${inputData}
</input_data>
`;

  const result = await genAI.models.generateContent({
    model: AGGREGATION_MODEL,
    contents: [{ role: "user", parts: [{ text: prompt }] }]
  });
  return result.text || "No report generated.";
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

