                  type: Type.STRING,
                  enum: ["frustrated", "helpful", "neutral", "absent"]
                },
                severity: {
                  type: Type.STRING,
                  enum: ["low", "medium", "high"]
                },
                resolution: {
                  type: Type.STRING,
                  enum: ["success", "failure", "partial"]
                },
                details: { type: Type.STRING },
                user_quote: { type: Type.STRING }
              },
              required: [
                "task_description",
                "friction_type",
                "root_cause",
                "user_sentiment",
                "severity",
                "resolution",
                "details"
              ]
            }
          },
          tools: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                category: { type: Type.STRING },
                specific_tool: { type: Type.STRING },
                params: { type: Type.STRING },
                usage_pattern: {
                  type: Type.STRING,
                  enum: [
                    "standard",
                    "workaround",
                    "exploration",
                    "verification",
                    "other"
                  ]
                },
                effectiveness: {
                  type: Type.STRING,
                  enum: ["high", "medium", "low", "failed"]
                },
                gap_identified: { type: Type.BOOLEAN },
                human_suggested: { type: Type.BOOLEAN },
                notes: { type: Type.STRING }
              },
              required: [
                "category",
                "specific_tool",
                "usage_pattern",
                "effectiveness",
                "gap_identified",
                "human_suggested"
              ]
            }
          }
        }
      }
    }
