  let totalRetries = 0;

  const processLogFileWrapper = async (
    filePath: string
  ): Promise<BaseProcessResult<CombinedInsight> | null> => {
    return runWithRetry(() => processLogFile(filePath, genAI), {
      maxRetries: MAX_RETRIES_PER_REQUEST,
