                  ]
                },
                user_sentiment: {
                  type: Type.STRING,
                  enum: ["frustrated", "helpful", "neutral", "absent"]
                },
                severity: {
                  type: Type.STRING,
                  enum: ["low", "medium", "high"]
                },
                resolution: {
                  type: Type.STRING,
