          friction_points: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                task_description: { type: Type.STRING },
                friction_type: {
                  type: Type.STRING,
                  enum: [
                    "autonomous_retry",
                    "user_intervention",
                    "hunting",
                    "repetition",
                    "tool_failure",
                    "other"
                  ]
                },
                root_cause: {
                  type: Type.STRING,
                  enum: [
                    "environment_issue",
                    "model_hallucination",
                    "tool_limitation",
                    "user_ambiguity",
                    "complex_task",
                    "unknown"
                  ]
                },
                user_sentiment: {
                  type: Type.STRING,
                  enum: ["frustrated", "helpful", "neutral", "absent"]
                },
                severity: {
                  type: Type.STRING,
                  enum: ["low", "medium", "high"]
                },
                resolution: {
                  type: Type.STRING,
                  enum: ["success", "failure", "partial"]
                },
                details: { type: Type.STRING },
                user_quote: { type: Type.STRING }
              },
              required: [
                "task_description",
                "friction_type",
                "root_cause",
                "user_sentiment",
                "severity",
                "resolution",
                "details"
              ]
            }
          },
          tools: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                category: { type: Type.STRING },
                specific_tool: { type: Type.STRING },
                params: { type: Type.STRING },
                usage_pattern: {
                  type: Type.STRING,
                  enum: [
                    "standard",
                    "workaround",
                    "exploration",
                    "verification",
                    "other"
                  ]
                },
                effectiveness: {
                  type: Type.STRING,
                  enum: ["high", "medium", "low", "failed"]
                },
                gap_identified: { type: Type.BOOLEAN },
                human_suggested: { type: Type.BOOLEAN },
                notes: { type: Type.STRING }
              },
              required: [
                "category",
                "specific_tool",
                "usage_pattern",
                "effectiveness",
                "gap_identified",
                "human_suggested"
              ]
            }
          }
        }
      }
    }
  });

  const text = result.text;
  if (!text) return null;

  let data;
  try {
    data = JSON.parse(text);
  } catch {
    console.error(`Failed to parse JSON for \${path.basename(filePath)}`);
    return null;
  }

  data.sessionFile = filePath;

  return {
    insight: data,
    rawSize: rawSize,
    filteredSize: filteredSize
  };
}

