          missing_capabilities: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                task_attempted: { type: Type.STRING },
                missing_sense_or_actuator: { type: Type.STRING },
                agent_response: {
                  type: Type.STRING,
                  enum: ["failed", "hallucinated_success", "asked_user"]
                },
                details: { type: Type.STRING }
              },
              required: ["task_attempted", "missing_sense_or_actuator", "agent_response", "details"]
            }
          },
          illegible_environments: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                tool_used: { type: Type.STRING },
                issue_type: {
                  type: Type.STRING,
                  enum: ["truncated_output", "cryptic_error", "massive_trace", "silent_failure", "other"]
                },
                impact: {
                  type: Type.STRING,
                  enum: ["context_destroyed", "confusion", "false_positive"]
                },
                details: { type: Type.STRING }
              },
              required: ["tool_used", "issue_type", "impact", "details"]
            }
          },
          flaky_or_slow_tools: {
             type: Type.ARRAY,
             items: {
               type: Type.OBJECT,
               properties: {
                 tool_used: { type: Type.STRING },
                 issue_type: {
                   type: Type.STRING,
                   enum: ["flaky", "slow"]
                 },
                 impact_on_loop: { type: Type.STRING },
                 details: { type: Type.STRING }
               },
               required: ["tool_used", "issue_type", "impact_on_loop", "details"]
             }
          },
          stubborn_workarounds: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                goal: { type: Type.STRING },
                workaround_sequence: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                custom_script_written: { type: Type.BOOLEAN },
                success: { type: Type.BOOLEAN },
                details: { type: Type.STRING }
              },
              required: ["goal", "workaround_sequence", "custom_script_written", "success", "details"]
            }
          }
        }
      }
    }
  });

  const text = result.text;
  if (!text) return null;

  let data;
  try {
    data = JSON.parse(text);
  } catch {
    console.error(`Failed to parse JSON for ${path.basename(filePath)}`);
    return null;
  }

  data.sessionFile = filePath;

