                issue_type: {
                  type: Type.STRING,
                  enum: [
                    "truncated_output",
                    "cryptic_error",
                    "massive_trace",
                    "silent_failure",
                    "other"
                  ]
                },
                impact: {
                  type: Type.STRING,
                  enum: ["context_destroyed", "confusion", "false_positive"]
                },
                details: { type: Type.STRING }
              },
              required: [
                "tool_used",
                "tool_type",
                "issue_type",
                "impact",
                "details"
              ]
            }
          },
          flaky_or_slow_tools: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                tool_used: { type: Type.STRING },
                tool_type: { type: Type.STRING, enum: ["system", "custom"] },
                issue_type: {
                  type: Type.STRING,
                  enum: ["flaky", "slow"]
                },
                impact_on_loop: { type: Type.STRING },
                details: { type: Type.STRING }
              },
              required: [
                "tool_used",
                "tool_type",
                "issue_type",
                "impact_on_loop",
                "details"
              ]
            }
          },
          stubborn_workarounds: {
